class ProfileService:
    def __init__(self, repository):
        self.repository = repository

    def update(self, payload):
        return self.repository.build_update(payload)

class ProfileRepository:
    def build_update(self, payload):
        return {"name": payload["name"]}

    def save(self, update):
        self.database.write(update)

export async function runWithRetry(job: () => Promise<void>) {
  for (let attempt = 0; attempt < 3; attempt += 1) {
    try { await job(); return; } catch (error) {
      if (attempt === 2) throw error;
    }
  }
}

package breaker

type State int
const ( Closed State = iota; Open )
type Breaker struct { state State; successes int }

func (b *Breaker) OnFailure() { b.state = Open; b.successes = 0 }
func (b *Breaker) OnSuccess() {
    if b.state == Open { b.successes++ }
}
func (b *Breaker) Allow() bool { return b.state == Closed }

package framework;
public abstract class BasePublisher {
  protected void publish(Object event) {
    for (Listener listener : listeners) listener.onEvent(event);
  }
}

package orders;
public final class OrderService extends BasePublisher {
  public void submit(Order order) {
    publish(new OrderSubmitted(order.id()));
  }
}

